import { describe, expect, it, vi } from "vitest";

vi.mock("next/headers", () => ({
  cookies: () => ({
    get: (name: string) => (name === "pharmacy-session" ? { name, value: "r-pilot-1" } : undefined),
  }),
}));

import { SESSION_COOKIE, SESSION_MAX_AGE_SECONDS, getSession, getSessionOrThrow } from "./session";

describe("lib/auth/session", () => {
  it("declares the canonical cookie name", () => {
    expect(SESSION_COOKIE).toBe("pharmacy-session");
  });

  it("declares a 30-day max-age in seconds", () => {
    expect(SESSION_MAX_AGE_SECONDS).toBe(60 * 60 * 24 * 30);
  });

  it("returns the retailerId from the cookie when present", () => {
    expect(getSession()).toEqual({ retailerId: "r-pilot-1" });
    expect(getSessionOrThrow()).toEqual({ retailerId: "r-pilot-1" });
  });
});

import { describe, expect, it, vi } from "vitest";

vi.mock("next/server", () => ({
  NextResponse: {
    next: () => ({ kind: "next" }),
    json: (body: unknown, init: { status: number }) => ({ kind: "json", body, status: init.status }),
    redirect: (url: { pathname: string }) => ({ kind: "redirect", to: url.pathname }),
  },
}));

import { middleware } from "./middleware";

function makeReq(pathname: string, hasCookie: boolean) {
  return {
    nextUrl: {
      pathname,
      clone: () => ({ pathname }),
    },
    cookies: { get: (n: string) => (hasCookie && n === "pharmacy-session" ? { value: "r-pilot-1" } : undefined) },
  } as unknown as Parameters<typeof middleware>[0];
}

describe("middleware", () => {
  it("lets non-matched paths through", () => {
    expect((middleware(makeReq("/random", false)) as { kind: string }).kind).toBe("next");
  });

  it("lets /api/auth/login through without a cookie", () => {
    expect((middleware(makeReq("/api/auth/login", false)) as { kind: string }).kind).toBe("next");
  });

  it("returns 401 JSON for /api/cart without a cookie", () => {
    const r = middleware(makeReq("/api/cart", false)) as { kind: string; status: number };
    expect(r.kind).toBe("json");
    expect(r.status).toBe(401);
  });

  it("redirects /dashboard/home to / without a cookie", () => {
    const r = middleware(makeReq("/dashboard/home", false)) as { kind: string; to: string };
    expect(r.kind).toBe("redirect");
    expect(r.to).toBe("/");
  });

  it("lets /dashboard/cart through with a cookie", () => {
    expect((middleware(makeReq("/dashboard/cart", true)) as { kind: string }).kind).toBe("next");
  });
});
